import{_ as t,p as d,q as r,a1 as e}from"./framework-5866ffd3.js";const a={},i=e('<h1 id="常用内置特性" tabindex="-1"><a class="header-anchor" href="#常用内置特性" aria-hidden="true">#</a> 常用内置特性</h1><p>内置特性指框架内提供的一些特性，拿来即用就能满足一般情况下的各种应用。当然，开发者也可以在实际应用中，编写满足特定场景需求的特性，然后将自定义特性修饰到接口、方法或参数即可。</p><blockquote><p>执行前顺序</p></blockquote><p>参数值验证 -&gt; IApiActionAttribute -&gt; IApiParameterAttribute -&gt; IApiReturnAttribute -&gt; IApiFilterAttribute</p><blockquote><p>执行后顺序</p></blockquote><p>IApiReturnAttribute -&gt; 返回值验证 -&gt; IApiFilterAttribute</p><h2 id="return特性" tabindex="-1"><a class="header-anchor" href="#return特性" aria-hidden="true">#</a> Return特性</h2><table><thead><tr><th>特性名称</th><th>功能描述</th><th>备注</th></tr></thead><tbody><tr><td>RawReturnAttribute</td><td>处理原始类型返回值</td><td>缺省也生效</td></tr><tr><td>JsonReturnAttribute</td><td>处理Json模型返回值</td><td>缺省也生效</td></tr><tr><td>XmlReturnAttribute</td><td>处理Xml模型返回值</td><td>缺省也生效</td></tr><tr><td>NoneReturnAttribute</td><td>处理空返回值</td><td>缺省也生效</td></tr></tbody></table><h2 id="常用action特性" tabindex="-1"><a class="header-anchor" href="#常用action特性" aria-hidden="true">#</a> 常用Action特性</h2><table><thead><tr><th>特性名称</th><th>功能描述</th><th>备注</th></tr></thead><tbody><tr><td>HttpHostAttribute</td><td>请求服务http绝对完整主机域名</td><td>优先级比Options配置低</td></tr><tr><td>HttpGetAttribute</td><td>声明Get请求方法与路径</td><td>支持null、绝对或相对路径</td></tr><tr><td>HttpPostAttribute</td><td>声明Post请求方法与路径</td><td>支持null、绝对或相对路径</td></tr><tr><td>HttpPutAttribute</td><td>声明Put请求方法与路径</td><td>支持null、绝对或相对路径</td></tr><tr><td>HttpDeleteAttribute</td><td>声明Delete请求方法与路径</td><td>支持null、绝对或相对路径</td></tr><tr><td><em>HeaderAttribute</em></td><td>声明请求头</td><td>常量值</td></tr><tr><td><em>TimeoutAttribute</em></td><td>声明超时时间</td><td>常量值</td></tr><tr><td><em>FormFieldAttribute</em></td><td>声明Form表单字段与值</td><td>常量键和值</td></tr><tr><td><em>FormDataTextAttribute</em></td><td>声明FormData表单字段与值</td><td>常量键和值</td></tr></tbody></table><h2 id="常用parameter特性" tabindex="-1"><a class="header-anchor" href="#常用parameter特性" aria-hidden="true">#</a> 常用Parameter特性</h2><table><thead><tr><th>特性名称</th><th>功能描述</th><th>备注</th></tr></thead><tbody><tr><td>PathQueryAttribute</td><td>参数值的键值对作为url路径参数或query参数的特性</td><td>缺省特性的参数默认为该特性</td></tr><tr><td>FormContentAttribute</td><td>参数值的键值对作为x-www-form-urlencoded表单</td><td></td></tr><tr><td>FormDataContentAttribute</td><td>参数值的键值对作为multipart/form-data表单</td><td></td></tr><tr><td>JsonContentAttribute</td><td>参数值序列化为请求的json内容</td><td></td></tr><tr><td>XmlContentAttribute</td><td>参数值序列化为请求的xml内容</td><td></td></tr><tr><td>UriAttribute</td><td>参数值作为请求uri</td><td>只能修饰第一个参数</td></tr><tr><td>ParameterAttribute</td><td>聚合性的请求参数声明</td><td>不支持细颗粒配置</td></tr><tr><td><em>HeaderAttribute</em></td><td>参数值作为请求头</td><td></td></tr><tr><td><em>TimeoutAttribute</em></td><td>参数值作为超时时间</td><td>值不能大于HttpClient的Timeout属性</td></tr><tr><td><em>FormFieldAttribute</em></td><td>参数值作为Form表单字段与值</td><td>只支持简单类型参数</td></tr><tr><td><em>FormDataTextAttribute</em></td><td>参数值作为FormData表单字段与值</td><td>只支持简单类型参数</td></tr></tbody></table><h2 id="filter特性" tabindex="-1"><a class="header-anchor" href="#filter特性" aria-hidden="true">#</a> Filter特性</h2><table><thead><tr><th>特性名称</th><th>功能描述</th><th>备注</th></tr></thead><tbody><tr><td>ApiFilterAttribute</td><td>Filter特性抽象类</td><td></td></tr><tr><td>LoggingFilterAttribute</td><td>请求和响应内容的输出为日志的过滤器</td><td></td></tr></tbody></table><h2 id="自解释参数类型" tabindex="-1"><a class="header-anchor" href="#自解释参数类型" aria-hidden="true">#</a> 自解释参数类型</h2><table><thead><tr><th>类型名称</th><th>功能描述</th><th>备注</th></tr></thead><tbody><tr><td>FormDataFile</td><td>form-data的一个文件项</td><td>无需特性修饰，等效于FileInfo类型</td></tr><tr><td>JsonPatchDocument</td><td>表示将JsonPatch请求文档</td><td>无需特性修饰</td></tr></tbody></table>',16),h=[i];function o(u,n){return d(),r("div",null,h)}const l=t(a,[["render",o],["__file","attribute.html.vue"]]);export{l as default};
